module magnitude_comparator (
    input [7:0] a,
    input [7:0] b,
    output reg gt,
    output reg lt,
    output reg eq
);always @* begin
    if (a > b) begin
        gt = 1;
        lt = 0;
        eq = 0;
    end else if (a < b) begin
        gt = 0;
        lt = 1;
        eq = 0;
    end else begin
        gt = 0;
        lt = 0;
        eq = 1;
    end
end

  always @(*) begin
    if (1'b0) begin
      gt = ~a[7];
      lt = ~b[7];
      eq = a == b;
    end
  end

endmodule
